@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #ededed;
  --color-neutral-200: #cccccc;
  --color-neutral-300: #b0b0b0;
  --color-neutral-400: #a0a0a0;
  --color-neutral-500: #8b9092;
  --color-neutral-600: #7e7e7e;
  --color-neutral-700: #707070;
  --color-neutral-800: #525252;
  --color-neutral-900: #464444;
  --color-neutral-950: #2e2e2e;
  --color-pale-green: #dffff1;
  --color-green: #3ecf8e;
  --color-deep-teal: #061517;
  --color-deep-teal-2: #163837;
  --color-orange: #ffcda1;
  --color-indigo: #bda4ff;
  --color-orange-2: #f1a10d;
  --color-cyan: #0070f3;
  --color-green-2: #1a7a4c;
  --color-blue: #6453c5;
  --color-indigo-2: #6b35dc;
  --color-blue-2: #32325d;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #2e2e2e;
  --color-text-muted: #7e7e7e;
  --color-surface: #ededed;
  --color-hairline: #cccccc;
  --color-accent: #dffff1;
  --color-accent-2: #3ecf8e;
  --color-accent-3: #061517;

  --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "Source Code Pro", ui-monospace, monospace;

  --text-xs: 0.625rem;
  --text-sm: 0.6875rem;
  --text-base: 0.75rem;
  --text-lg: 0.8rem;
  --text-xl: 0.875rem;
  --text-2xl: 0.9rem;
  --text-3xl: 1rem;
  --text-4xl: 1.2rem;
  --text-5xl: 1.25rem;
  --text-6xl: 1.75rem;
  --text-7xl: 2rem;
  --text-8xl: 2.25rem;

  --font-weight-thin: 100;
  --font-weight-extralight: 200;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.11;
  --leading-snug: 1.33;
  --leading-normal: 1.43;
  --leading-relaxed: 1.5;
  --leading-loose: 1.6;
  --leading-looser: 1.71;
  --leading-loosest: 1.75;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -1.5px;
  --tracking-tighter: -1.1px;
  --tracking-tight: -.5px;
  --tracking-normal: -.025em;
  --tracking-wide: -.01rem;
  --tracking-wider: -.15px;

  --radius-sm: 2px;
  --radius-md: .25rem;
  --radius-lg: 6px;
  --radius-xl: 8px;
  --radius-2xl: 14px;
  --radius-3xl: 20px;
  --radius-4xl: 100%;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 13px 27px -5px rgba(50,50,93,.25),0 8px 16px -8px rgba(0,0,0,.3),0 -6px 16px -6px rgba(0,0,0,.025);

  --breakpoint-sm: 30rem;
  --breakpoint-md: 32.5rem;
  --breakpoint-lg: 37.5rem;
  --breakpoint-xl: 40rem;
  --breakpoint-2xl: 45rem;
  --breakpoint-3xl: 48rem;
  --breakpoint-4xl: 48.0625rem;
  --breakpoint-5xl: 60rem;

  /* most-used spacing values on the source site (px): 1, 2, 3, 4, 5, 6, 8, 10, 12, 15, 16, 48 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --ch-0: dark;
    --ch-1: #8b949e;
    --ch-2: #79c0ff;
    --ch-3: #ffcda1;
    --ch-4: #f8f8f2;
    --ch-5: #bda4ff;
    --ch-6: hsl(var(--brand-600));
    --ch-7: #569cd6;
    --ch-8: hsl(var(--brand-default));
    --ch-9: #ffa198;
    --ch-10: #f0f6fc;
    --ch-11: #490202;
    --ch-12: #04260f;
    --ch-13: #5a1e02;
    --ch-14: #161b22;
    --ch-15: #8b949e;
    --ch-16: #2a2929;
    --ch-17: #264f78;
    --ch-18: #3794ff;
    --ch-19: #ffffff0b;
    --ch-20: #6e7681;
    --ch-21: #010409;
    --ch-22: #30363d;
    --ch-23: #f78166;
    --ch-24: #6e768166;
    --ch-25: #6e76811a;
    --tw-brightness: brightness(200%);
    --tw-contrast: contrast(0%);
    --tw-gradient-position: to bottom;
    --tw-gradient-to: hsl(var(--background-surface-100));
    --tw-shadow: 0px 0px 6px 0px var(--tw-shadow-color,#2cf49466);
    --tw-blur: blur(24px);
    --tw-invert: invert(100%);
    --tw-saturate: saturate(.4);
    --tw-gradient-from: #0003;
    --tw-ring-color: hsl(var(--destructive-default));
    --helpers-os-appearance: Dark;
    --code-block-5: 13.8deg 89.7% 69.6%;
    --code-block-4: 276.1deg 67.7% 74.5%;
    --code-block-3: 83.8deg 61.7% 63.1%;
    --code-block-2: 33.2deg 90.3% 75.7%;
    --code-block-1: 170.8deg 43.1% 61.4%;
    --secondary-default: 247.8deg 100% 70%;
    --secondary-400: 248.3deg 54.5% 25.9%;
    --secondary-200: 248deg 53.6% 11%;
    --brand-link: 155deg 100% 38.6%;
    --brand-default: 153.1deg 60.2% 52.7%;
    --brand-600: 154.9deg 59.5% 70%;
    --brand-500: 154.9deg 100% 19.2%;
    --brand-400: 155.5deg 100% 9.6%;
    --brand-300: 155.1deg 100% 8%;
    --brand-200: 162deg 100% 2%;
    --warning-default: 38.9deg 100% 42.9%;
    --warning-600: 38.9deg 100% 42.9%;
    --warning-500: 34.8deg 90.9% 21.6%;
    --warning-400: 33.2deg 100% 14.5%;
    --warning-300: 32.3deg 100% 10.2%;
    --warning-200: 36.6deg 100% 8%;
    --destructive-default: 10.2deg 77.9% 53.9%;
    --destructive-600: 9.7deg 85.2% 62.9%;
  }
}

